import{_ as t,o as e,c as i,a2 as l}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"RICE 与 Value/Effort 排序","description":"","frontmatter":{"title":"RICE 与 Value/Effort 排序","stage":"intermediate","direction":"product","tags":["产品","中级","优先级","RICE"]},"headers":[],"relativePath":"02-product/notes/03-requirements-prioritization/07-rice-value-effort.md","filePath":"02-product/notes/03-requirements-prioritization/07-rice-value-effort.md","lastUpdated":null}'),s={name:"02-product/notes/03-requirements-prioritization/07-rice-value-effort.md"};function n(r,a,d,h,p,o){return e(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="rice-与-value-effort-排序" tabindex="-1">RICE 与 Value/Effort 排序 <a class="header-anchor" href="#rice-与-value-effort-排序" aria-label="Permalink to &quot;RICE 与 Value/Effort 排序&quot;">​</a></h1><p>RICE 与 Value/Effort 是在候选事项之间建立一致比较口径的方法。它们压缩证据以支持讨论，不会自动证明某项值得做，也不能取代安全、合规、战略边界和产品判断。</p><h2 id="前置知识" tabindex="-1">前置知识 <a class="header-anchor" href="#前置知识" aria-label="Permalink to &quot;前置知识&quot;">​</a></h2><ul><li>候选事项指向清楚的用户问题与产品目标。</li><li>成功指标有分析单位、分母、时间窗和质量门槛。</li><li>能估算端到端工作，而非只估开发编码。</li><li>能区分事实、假设和主观尺度。</li><li>已识别不可用收益交换的硬约束。</li></ul><h2 id="一、先决定哪些事项可以被排序" tabindex="-1">一、先决定哪些事项可以被排序 <a class="header-anchor" href="#一、先决定哪些事项可以被排序" aria-label="Permalink to &quot;一、先决定哪些事项可以被排序&quot;">​</a></h2><p>不是所有工作都应进入同一张分数表。</p><h3 id="先走门槛的事项" tabindex="-1">先走门槛的事项 <a class="header-anchor" href="#先走门槛的事项" aria-label="Permalink to &quot;先走门槛的事项&quot;">​</a></h3><ul><li>已确认的安全漏洞。</li><li>法规与合同固定期限。</li><li>账务、授权和数据一致性缺陷。</li><li>可靠性目标已经越界的修复。</li><li>产品明确承诺且取消成本不可接受的迁移。</li></ul><p>这些事项先判断必须做、截止日期和最小安全范围。把它们与增长实验比较 RICE，可能得出“漏洞触达人数少所以延后”的错误结论。</p><h3 id="可以相对排序的事项" tabindex="-1">可以相对排序的事项 <a class="header-anchor" href="#可以相对排序的事项" aria-label="Permalink to &quot;可以相对排序的事项&quot;">​</a></h3><p>候选项需要：</p><ul><li>处于同一产品目标或资金池。</li><li>使用相近的时间窗。</li><li>Reach 使用同一种受益单位。</li><li>Impact 使用同一尺度。</li><li>Effort 覆盖相同角色与生命周期。</li><li>没有尚未通过的硬门槛。</li></ul><p>一个面向季度激活的功能和一个面向三年基础设施迁移的项目，通常不应直接用同一分数排成线性列表。</p><h2 id="二、rice-的四个输入" tabindex="-1">二、RICE 的四个输入 <a class="header-anchor" href="#二、rice-的四个输入" aria-label="Permalink to &quot;二、RICE 的四个输入&quot;">​</a></h2><p>常见形式：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>RICE = Reach × Impact × Confidence / Effort</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>分数没有天然单位。只有在同一批候选中使用一致口径时，大小才有比较意义。</p><h3 id="reach-触达" tabindex="-1">Reach：触达 <a class="header-anchor" href="#reach-触达" aria-label="Permalink to &quot;Reach：触达&quot;">​</a></h3><p>Reach 表示固定时间窗内可能从事项中受益的唯一分析单位。</p><p>定义必须包含：</p><ul><li>对象：用户、账户、订单、工作区还是任务。</li><li>资格：哪些对象有机会遇到问题。</li><li>窗口：月、季度或发布后 90 天。</li><li>去重：同一对象多次行为如何处理。</li><li>来源：事件、日志、订单或可追踪证据。</li></ul><p>错误示例：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Reach = 页面浏览量 50,000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>页面浏览量包含重复访问，也可能包含不会使用目标能力的人。</p><p>更合格的定义：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Reach = 未来一个季度中，</span></span>
<span class="line"><span>至少一次提交英文以外搜索词、</span></span>
<span class="line"><span>且有文档访问权限的唯一工作区数。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Reach 不是总用户规模。如果能力只对管理员生效，分母应先筛选有资格的管理员或工作区。</p><h3 id="impact-影响" tabindex="-1">Impact：影响 <a class="header-anchor" href="#impact-影响" aria-label="Permalink to &quot;Impact：影响&quot;">​</a></h3><p>Impact 表示每个被触达单位对目标结果的预期变化。没有可直接估算的数据时，可以使用事先固定的离散尺度。</p><p>示例尺度：</p><table tabindex="0"><thead><tr><th style="text-align:right;">分值</th><th>语义</th></tr></thead><tbody><tr><td style="text-align:right;">3</td><td>可能直接改变核心结果</td></tr><tr><td style="text-align:right;">2</td><td>对核心结果有明显作用</td></tr><tr><td style="text-align:right;">1</td><td>有可观察但有限的作用</td></tr><tr><td style="text-align:right;">0.5</td><td>辅助作用</td></tr><tr><td style="text-align:right;">0.25</td><td>很弱或间接作用</td></tr></tbody></table><p>数字只是标签。不能说 2 分必然是 1 分的两倍，除非团队用真实结果单位定义了比例。</p><p>Impact 应连接目标。例如“减少导入失败”不能使用“视觉更统一”的影响判断，除非能说明视觉变化怎样影响任务完成。</p><h3 id="confidence-置信度" tabindex="-1">Confidence：置信度 <a class="header-anchor" href="#confidence-置信度" aria-label="Permalink to &quot;Confidence：置信度&quot;">​</a></h3><p>Confidence 表示输入与机制证据的可信程度，不是团队支持率。</p><p>可按证据层级设置规则：</p><table tabindex="0"><thead><tr><th style="text-align:right;">置信度</th><th>证据条件示例</th></tr></thead><tbody><tr><td style="text-align:right;">90%</td><td>目标群体的行为数据和小规模验证方向一致</td></tr><tr><td style="text-align:right;">70%</td><td>多来源问题证据充分，但方案效果尚未验证</td></tr><tr><td style="text-align:right;">50%</td><td>有重复信号，口径或因果机制仍不清</td></tr><tr><td style="text-align:right;">30%</td><td>主要来自单一请求、竞品模仿或内部观点</td></tr></tbody></table><p>同为 70% 的两项不表示概率经过统计估计，而表示按照团队规则处于同一证据等级。</p><p>不要用 Confidence 掩盖完全未知的关键假设。若价值假设失败会推翻方案，先验证可能比给低分更合理。</p><h3 id="effort-工作量" tabindex="-1">Effort：工作量 <a class="header-anchor" href="#effort-工作量" aria-label="Permalink to &quot;Effort：工作量&quot;">​</a></h3><p>Effort 是实现、验证、发布和维持候选项所需的总投入，通常以人周或人月表示。</p><p>应包含：</p><ul><li>产品定义与规则梳理。</li><li>交互与内容设计。</li><li>前端、后端、客户端和数据工作。</li><li>安全、隐私和合规评审。</li><li>测试、迁移、灰度和回滚。</li><li>埋点、看板和告警。</li><li>运营培训与支持准备。</li><li>功能标记清理和长期维护。</li></ul><p>不同角色并行不等于成本消失。例如产品 1 周、设计 1 周、开发 3 周、测试 1 周，总 Effort 可以是 6 人周，即使日历时间只有 3 周。</p><h2 id="三、value-effort" tabindex="-1">三、Value/Effort <a class="header-anchor" href="#三、value-effort" aria-label="Permalink to &quot;三、Value/Effort&quot;">​</a></h2><p>Value/Effort 用更少输入做粗粒度比较：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>优先级倾向 = Value / Effort</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Value 可以包含用户价值、业务价值、风险降低和战略能力，但必须分别定义。若把四种价值直接合成一个“高、中、低”，会隐藏分歧。</p><h3 id="二维矩阵" tabindex="-1">二维矩阵 <a class="header-anchor" href="#二维矩阵" aria-label="Permalink to &quot;二维矩阵&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>低 Effort</th><th>高 Effort</th></tr></thead><tbody><tr><td>高 Value</td><td>优先验证或交付</td><td>拆分、验证最大假设</td></tr><tr><td>低 Value</td><td>仅在机会成本很低时做</td><td>通常拒绝或延后</td></tr></tbody></table><p>矩阵适合候选多、证据粗的早期筛选。它不适合对得分接近的重大投资作最终决定。</p><h3 id="value-的拆分" tabindex="-1">Value 的拆分 <a class="header-anchor" href="#value-的拆分" aria-label="Permalink to &quot;Value 的拆分&quot;">​</a></h3><div class="language-yaml vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  user</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;减少目标任务失败&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  business</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;降低试用流失&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  risk_reduction</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;减少错误授权&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  strategic</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;形成后续企业能力&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>四项不能任意相加。错误授权属于硬门槛时，应先处理，而不是只作为一项加权价值。</p><h2 id="四、完整排序流程" tabindex="-1">四、完整排序流程 <a class="header-anchor" href="#四、完整排序流程" aria-label="Permalink to &quot;四、完整排序流程&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;候选事项&quot;] --&gt; B[&quot;按目标与资金池分组&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;硬门槛筛选&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;统一单位和窗口&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[&quot;记录原始输入与来源&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[&quot;计算基准分&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G[&quot;区间与敏感性分析&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[&quot;检查依赖和组合效应&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; I[&quot;形成顺序与验证计划&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h3 id="_1-分组" tabindex="-1">1. 分组 <a class="header-anchor" href="#_1-分组" aria-label="Permalink to &quot;1. 分组&quot;">​</a></h3><p>先按产品目标、用户群和决策期限分组。不同目标的预算分配是上层策略决定，不能靠单项分数偷偷完成。</p><h3 id="_2-门槛" tabindex="-1">2. 门槛 <a class="header-anchor" href="#_2-门槛" aria-label="Permalink to &quot;2. 门槛&quot;">​</a></h3><p>未通过安全、合规、可访问、数据可得和可恢复门槛的候选，不进入效用比较。</p><h3 id="_3-冻结尺度" tabindex="-1">3. 冻结尺度 <a class="header-anchor" href="#_3-冻结尺度" aria-label="Permalink to &quot;3. 冻结尺度&quot;">​</a></h3><p>在看具体候选分布前定义 Impact 与 Confidence 尺度，防止为了喜欢的方案调整标签。</p><h3 id="_4-保存来源" tabindex="-1">4. 保存来源 <a class="header-anchor" href="#_4-保存来源" aria-label="Permalink to &quot;4. 保存来源&quot;">​</a></h3><p>每个输入旁记录查询、样本窗口、估算参与者和限制。只保留最终分数无法复查。</p><h3 id="_5-使用区间" tabindex="-1">5. 使用区间 <a class="header-anchor" href="#_5-使用区间" aria-label="Permalink to &quot;5. 使用区间&quot;">​</a></h3><p>Reach、Impact 和 Effort 都可能不确定。至少计算悲观、基准、乐观三种情景。</p><h3 id="_6-做敏感性分析" tabindex="-1">6. 做敏感性分析 <a class="header-anchor" href="#_6-做敏感性分析" aria-label="Permalink to &quot;6. 做敏感性分析&quot;">​</a></h3><p>逐项改变关键输入，观察排名是否稳定。若小幅变化就逆转，应先验证或把两项视为同一优先级区间。</p><h3 id="_7-检查依赖" tabindex="-1">7. 检查依赖 <a class="header-anchor" href="#_7-检查依赖" aria-label="Permalink to &quot;7. 检查依赖&quot;">​</a></h3><p>高分事项可能依赖低分基础能力；两个候选也可能共享开发成本。单项分数不能表达组合效应，需要单独记录。</p><h3 id="_8-输出决定" tabindex="-1">8. 输出决定 <a class="header-anchor" href="#_8-输出决定" aria-label="Permalink to &quot;8. 输出决定&quot;">​</a></h3><p>输出不只是一列序号，还应包含：</p><ul><li>立即交付。</li><li>先验证关键假设。</li><li>等待依赖。</li><li>延后并设置复查条件。</li><li>拒绝及理由。</li></ul><h2 id="五、完整案例一-知识库搜索改进" tabindex="-1">五、完整案例一：知识库搜索改进 <a class="header-anchor" href="#五、完整案例一-知识库搜索改进" aria-label="Permalink to &quot;五、完整案例一：知识库搜索改进&quot;">​</a></h2><p>目标：提高工作区成员从搜索到打开有效文档的比例。季度候选：</p><ol><li>A：查询拼写纠正。</li><li>B：结果中显示命中段落。</li><li>C：语义检索。</li><li>D：保存最近搜索。</li></ol><h3 id="统一输入" tabindex="-1">统一输入 <a class="header-anchor" href="#统一输入" aria-label="Permalink to &quot;统一输入&quot;">​</a></h3><p>Reach 以“季度内至少一次出现零结果或立即改写查询的唯一工作区”为单位。Impact 使用固定 0.25、0.5、1、2、3 尺度。Effort 以总人月估算。</p><table tabindex="0"><thead><tr><th>候选</th><th style="text-align:right;">Reach</th><th style="text-align:right;">Impact</th><th style="text-align:right;">Confidence</th><th style="text-align:right;">Effort</th><th style="text-align:right;">RICE</th></tr></thead><tbody><tr><td>A 拼写纠正</td><td style="text-align:right;">1,200</td><td style="text-align:right;">1</td><td style="text-align:right;">80%</td><td style="text-align:right;">2</td><td style="text-align:right;">480</td></tr><tr><td>B 命中段落</td><td style="text-align:right;">2,000</td><td style="text-align:right;">0.5</td><td style="text-align:right;">90%</td><td style="text-align:right;">1.5</td><td style="text-align:right;">600</td></tr><tr><td>C 语义检索</td><td style="text-align:right;">1,600</td><td style="text-align:right;">2</td><td style="text-align:right;">50%</td><td style="text-align:right;">6</td><td style="text-align:right;">266.7</td></tr><tr><td>D 最近搜索</td><td style="text-align:right;">900</td><td style="text-align:right;">0.25</td><td style="text-align:right;">70%</td><td style="text-align:right;">1</td><td style="text-align:right;">157.5</td></tr></tbody></table><p>计算 A：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1200 × 1 × 0.8 / 2 = 480</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="初步结论" tabindex="-1">初步结论 <a class="header-anchor" href="#初步结论" aria-label="Permalink to &quot;初步结论&quot;">​</a></h3><p>B 得分最高，但这不表示直接全量上线。命中段落需要先通过权限片段不泄露和页面加载性能门槛。</p><p>C 的潜在影响高，但 Confidence 低且 Effort 大。它更适合先做离线评估和受控原型，而不是因总分低永久拒绝。</p><h3 id="敏感性分析" tabindex="-1">敏感性分析 <a class="header-anchor" href="#敏感性分析" aria-label="Permalink to &quot;敏感性分析&quot;">​</a></h3><p>B 的 Impact 若只有 0.25，则得分降至 300；A 仍为 480，排名逆转。B 的关键不确定性是片段是否真的提高有效文档打开，而不是实现能否完成。</p><p>于是形成的决定：</p><ul><li>A 进入开发。</li><li>B 先对 10% 稳定工作区验证片段价值。</li><li>C 先建立查询集与权限过滤评估。</li><li>D 延后，复查条件为重复查询工作区比例超过 30%。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若片段提高点击率但有效停留和后续任务完成下降，不能按点击率宣告成功。若权限过滤无法在片段级保持一致，B 直接阻塞，不用更高 RICE 抵消。</p><h2 id="六、完整案例二-结算可靠性" tabindex="-1">六、完整案例二：结算可靠性 <a class="header-anchor" href="#六、完整案例二-结算可靠性" aria-label="Permalink to &quot;六、完整案例二：结算可靠性&quot;">​</a></h2><p>目标：降低支付发起后订单结果未知的比例。候选：</p><ul><li>E：前端增加重试按钮。</li><li>F：服务端支付幂等与主动查询。</li><li>G：运营提供人工查询面板。</li><li>H：增加第二支付渠道。</li></ul><h3 id="为什么不能直接计算" tabindex="-1">为什么不能直接计算 <a class="header-anchor" href="#为什么不能直接计算" aria-label="Permalink to &quot;为什么不能直接计算&quot;">​</a></h3><p>当前服务端允许重复支付的风险属于账务硬门槛。F 中的幂等和状态收敛不是普通增长候选，必须先进入可靠性工作。</p><p>剩余增量能力再做 Value/Effort：</p><table tabindex="0"><thead><tr><th>候选</th><th>用户价值</th><th>风险降低</th><th style="text-align:right;">Effort</th><th>判断</th></tr></thead><tbody><tr><td>E 重试按钮</td><td>低；可能放大重复</td><td>负向</td><td style="text-align:right;">0.5 人月</td><td>拒绝</td></tr><tr><td>F 主动查询</td><td>高</td><td>高</td><td style="text-align:right;">2 人月</td><td>与幂等一起优先</td></tr><tr><td>G 查询面板</td><td>中</td><td>中</td><td style="text-align:right;">1 人月 + 持续人工</td><td>作为低量恢复</td></tr><tr><td>H 第二渠道</td><td>高</td><td>中</td><td style="text-align:right;">5 人月 + 运维</td><td>等基线与量级</td></tr></tbody></table><h3 id="生产成本" tabindex="-1">生产成本 <a class="header-anchor" href="#生产成本" aria-label="Permalink to &quot;生产成本&quot;">​</a></h3><p>G 的开发 Effort 低，但每周 100 笔、每笔 8 分钟会产生 13.3 小时持续人工成本。若只计算开发人月，G 会被错误排得过高。</p><h3 id="决定" tabindex="-1">决定 <a class="header-anchor" href="#决定" aria-label="Permalink to &quot;决定&quot;">​</a></h3><p>先完成 F，G 用作结果未知的限量恢复。H 的 Reach 只应计算主渠道不可用时受影响订单，而不是全部订单。E 因可能破坏幂等，不进入排序。</p><h2 id="七、区间估算" tabindex="-1">七、区间估算 <a class="header-anchor" href="#七、区间估算" aria-label="Permalink to &quot;七、区间估算&quot;">​</a></h2><p>假设候选 X：</p><ul><li>Reach：800–1,200。</li><li>Impact：1–2。</li><li>Confidence：50%–80%。</li><li>Effort：2–4 人月。</li></ul><p>悲观：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>800 × 1 × 0.5 / 4 = 100</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>乐观：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1200 × 2 × 0.8 / 2 = 960</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>100 到 960 的区间说明当前输入不足。给出基准 400 并不会让结论可靠。应找出贡献最大的不确定项：通常先验证 Impact 或缩小 Effort 估算范围。</p><h3 id="蒙特卡洛是否必要" tabindex="-1">蒙特卡洛是否必要 <a class="header-anchor" href="#蒙特卡洛是否必要" aria-label="Permalink to &quot;蒙特卡洛是否必要&quot;">​</a></h3><p>当项目重大且已有可描述的输入分布时，可以模拟分数分布；但模拟不会改善错误口径。若 Reach 分母就选错，生成更多随机数只会更精确地重复错误。</p><h2 id="八、依赖、组合与时间" tabindex="-1">八、依赖、组合与时间 <a class="header-anchor" href="#八、依赖、组合与时间" aria-label="Permalink to &quot;八、依赖、组合与时间&quot;">​</a></h2><h3 id="依赖" tabindex="-1">依赖 <a class="header-anchor" href="#依赖" aria-label="Permalink to &quot;依赖&quot;">​</a></h3><p>候选 C 依赖统一权限过滤 P。单独给 P 的用户 Impact 可能很低，但没有 P，C、推荐和摘要都不能安全上线。应把 P 作为平台门槛或组合投资评估。</p><h3 id="共享成本" tabindex="-1">共享成本 <a class="header-anchor" href="#共享成本" aria-label="Permalink to &quot;共享成本&quot;">​</a></h3><p>若 A 与 B 共享查询日志改造，分别估算会重复计算。可以比较组合：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A 单独：2 人月</span></span>
<span class="line"><span>B 单独：1.5 人月</span></span>
<span class="line"><span>A+B：2.7 人月</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="成本延迟" tabindex="-1">成本延迟 <a class="header-anchor" href="#成本延迟" aria-label="Permalink to &quot;成本延迟&quot;">​</a></h3><p>有截止窗口的价值会随时间衰减。例如税务规则必须在生效日前完成。RICE 不直接表示延迟成本，应在时间约束中单独处理。</p><h3 id="可逆性" tabindex="-1">可逆性 <a class="header-anchor" href="#可逆性" aria-label="Permalink to &quot;可逆性&quot;">​</a></h3><p>证据弱时，可灰度、可关闭、无数据迁移的候选比不可逆架构改造更适合先行。可逆性可以作为门槛或单独决策字段，不建议随意塞入 Impact。</p><h2 id="九、常见操纵与修正" tabindex="-1">九、常见操纵与修正 <a class="header-anchor" href="#九、常见操纵与修正" aria-label="Permalink to &quot;九、常见操纵与修正&quot;">​</a></h2><table tabindex="0"><thead><tr><th>操纵</th><th>表现</th><th>修正</th></tr></thead><tbody><tr><td>放大 Reach</td><td>用总注册或浏览量</td><td>使用有资格唯一单位</td></tr><tr><td>放大 Impact</td><td>把愿景当单项效果</td><td>固定尺度并连接目标</td></tr><tr><td>放大 Confidence</td><td>用支持者人数</td><td>按证据等级赋值</td></tr><tr><td>缩小 Effort</td><td>只估编码</td><td>包含发布、运营和退役</td></tr><tr><td>改变窗口</td><td>不同候选用月与年</td><td>统一决策窗口</td></tr><tr><td>忽略守护</td><td>高增长掩盖风险</td><td>硬门槛先于评分</td></tr><tr><td>小数制造精确</td><td>输入粗糙却报 266.67</td><td>保留合理有效位和区间</td></tr><tr><td>分数永久有效</td><td>使用过期 Reach</td><td>设置数据日期和复查</td></tr></tbody></table><h2 id="十、调试排序争议" tabindex="-1">十、调试排序争议 <a class="header-anchor" href="#十、调试排序争议" aria-label="Permalink to &quot;十、调试排序争议&quot;">​</a></h2><h3 id="先定位分歧字段" tabindex="-1">先定位分歧字段 <a class="header-anchor" href="#先定位分歧字段" aria-label="Permalink to &quot;先定位分歧字段&quot;">​</a></h3><p>不要争论“谁更重要”，逐项比较 Reach 定义、Impact 机制、Confidence 证据和 Effort 范围。分歧往往集中在一个输入。</p><h3 id="回到原始证据" tabindex="-1">回到原始证据 <a class="header-anchor" href="#回到原始证据" aria-label="Permalink to &quot;回到原始证据&quot;">​</a></h3><p>抽查事件资格集合、去重和时间窗；检查 Impact 证据是否来自同类用户；检查 Effort 是否遗漏迁移、第三方和人工成本。</p><h3 id="运行尺度校准" tabindex="-1">运行尺度校准 <a class="header-anchor" href="#运行尺度校准" aria-label="Permalink to &quot;运行尺度校准&quot;">​</a></h3><p>挑选三个已完成事项，用当时可得证据重新打分，再与实际结果比较。若团队持续高估某类 Impact 或低估运营成本，调整尺度规则。</p><h3 id="记录反对意见" tabindex="-1">记录反对意见 <a class="header-anchor" href="#记录反对意见" aria-label="Permalink to &quot;记录反对意见&quot;">​</a></h3><p>排序决定应保留未选方案、主要分歧和复查触发器。新证据出现时重新计算，而不是把旧分数当承诺。</p><h2 id="十一、综合练习" tabindex="-1">十一、综合练习 <a class="header-anchor" href="#十一、综合练习" aria-label="Permalink to &quot;十一、综合练习&quot;">​</a></h2><p>选择同一目标下至少六个候选事项：</p><ol><li>定义可比较集合和被排除的硬门槛事项。</li><li>写 Reach 对象、资格、窗口、去重和查询来源。</li><li>建立 Impact 与 Confidence 的固定尺度。</li><li>估算包含全生命周期的 Effort。</li><li>计算 RICE 基准值。</li><li>为三个关键输入给出区间。</li><li>做敏感性分析并标记排名不稳定项。</li><li>识别依赖、共享成本与组合。</li><li>输出交付、先验证、等待、延后、拒绝五类决定。</li><li>为每项决定设置复查触发器。</li></ol><h3 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h3><ul><li>所有 Reach 使用同一分析单位与窗口。</li><li>Impact 分值能追踪到明确尺度和目标机制。</li><li>Confidence 来自证据规则，而非投票。</li><li>Effort 包含设计、数据、测试、发布、运营和退役。</li><li>安全、合规与业务不变量没有进入收益交换。</li><li>分数接近时展示区间，不伪造精确顺序。</li><li>依赖和组合效应没有被单项分数隐藏。</li><li>另一名学习者可用原始输入复算并得到相同结果。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.intercom.com/blog/rice-simple-prioritization-for-product-managers/" target="_blank" rel="noreferrer">Intercom：RICE scoring model</a>（访问日期：2026-07-18）</li><li><a href="https://www.gov.uk/service-manual/agile-delivery/developing-a-roadmap" target="_blank" rel="noreferrer">GOV.UK Service Manual：Developing a roadmap</a>（访问日期：2026-07-18）</li><li><a href="https://www.gov.uk/service-manual/agile-delivery/governance-principles-for-agile-service-delivery" target="_blank" rel="noreferrer">GOV.UK Service Manual：Governance principles for agile service delivery</a>（访问日期：2026-07-18）</li></ul>`,139)])])}const b=t(s,[["render",n]]);export{u as __pageData,b as default};
